create function locomotif as 'org.apache.iotdb.library.dmatch.UDTFLoCoMotif'
create database root.locomotif_exp
create timeseries root.locomotif_exp.synthetic.s1 with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
create timeseries root.locomotif_exp.synthetic.s2 with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
create timeseries root.locomotif_exp.tsmd_mitdb1.s1 with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
