create timeseries root.locomotif_exp.tsmd_refit.s1 with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
create timeseries root.locomotif_exp.tsmd_refit.label with datatype=INT32, encoding=PLAIN, compression=UNCOMPRESSED
create timeseries root.locomotif_exp.pamap2.activity_id with datatype=INT32, encoding=PLAIN, compression=UNCOMPRESSED
