create timeseries root.locomotif_exp.pamap2.hand_acc_y with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
create timeseries root.locomotif_exp.pamap2.hand_acc_z with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
create timeseries root.locomotif_exp.pamap2.chest_acc_x with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
create timeseries root.locomotif_exp.pamap2.chest_acc_y with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
create timeseries root.locomotif_exp.pamap2.chest_acc_z with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
create timeseries root.locomotif_exp.pamap2.ankle_acc_x with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
create timeseries root.locomotif_exp.pamap2.ankle_acc_y with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
create timeseries root.locomotif_exp.pamap2.ankle_acc_z with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
create timeseries root.locomotif_exp.refit_house1.aggregate with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
create timeseries root.locomotif_exp.refit_house1.app1 with datatype=DOUBLE, encoding=PLAIN, compression=UNCOMPRESSED
